void run_eri_0030(double *eri, double ai, double aj, double ak, double al,
        double *Ra, double *Rb, double *Rc, double *Rd,
        void (*gamma_inc_fn)(int, double, double []))
{
    extern double exp(double);
    extern double sqrt(double);
    double aij = ai + aj;
    double akl = ak + al;
    double theta = aij * akl / (aij + akl);
    double Xab = Ra[0] - Rb[0];
    double Yab = Ra[1] - Rb[1];
    double Zab = Ra[2] - Rb[2];
    double Xcd = Rc[0] - Rd[0];
    double Ycd = Rc[1] - Rd[1];
    double Zcd = Rc[2] - Rd[2];
    double theta_rij = ai * aj / aij * (Xab*Xab+Yab*Yab+Zab*Zab);
    double theta_rkl = ak * al / akl * (Xcd*Xcd+Ycd*Ycd+Zcd*Zcd);
    double fac = 34.986836655249725; // 2*pi**2.5
    double Kabcd = fac / (aij*akl*sqrt(aij+akl)) * exp(-theta_rij - theta_rkl);
    if (Kabcd < 1e-16) {
        for (int i = 0; i < 10; i++) eri[i] = 0;
        return;
    }
    double Xp = (ai * Ra[0] + aj * Rb[0]) / aij;
    double Yp = (ai * Ra[1] + aj * Rb[1]) / aij;
    double Zp = (ai * Ra[2] + aj * Rb[2]) / aij;
    double Xq = (ak * Rc[0] + al * Rd[0]) / akl;
    double Yq = (ak * Rc[1] + al * Rd[1]) / akl;
    double Zq = (ak * Rc[2] + al * Rd[2]) / akl;
    double Xpq = Xp - Xq;
    double Ypq = Yp - Yq;
    double Zpq = Zp - Zq;
    double Xpa = Xp - Ra[0];
    double Ypa = Yp - Ra[1];
    double Zpa = Zp - Ra[2];
    double Xqc = Xq - Rc[0];
    double Yqc = Yq - Rc[1];
    double Zqc = Zq - Rc[2];
    double theta_r2 = theta * (Xpq*Xpq+Ypq*Ypq+Zpq*Zpq);
    double theta_aij = theta / aij;
    double theta_akl = theta / akl;
    double aij_akl = aij / akl;
    double aa = aij + akl;
    double Xtheta_aij = Xpq * theta_aij;
    double Ytheta_aij = Ypq * theta_aij;
    double Ztheta_aij = Zpq * theta_aij;
    double Xtheta_akl = Xpq * theta_akl;
    double Ytheta_akl = Ypq * theta_akl;
    double Ztheta_akl = Zpq * theta_akl;
    double _gamma_inc[32];
    gamma_inc_fn(4, theta_r2, _gamma_inc);
    double vrr_0_000 = Kabcd * _gamma_inc[0];
    double vrr_1_000 = Kabcd * _gamma_inc[1];
    double e_trans0_000_100 = Xqc * (vrr_0_000) + Xtheta_akl * (vrr_1_000);
    double vrr_2_000 = Kabcd * _gamma_inc[2];
    double e_trans1_000_100 = Xqc * (vrr_1_000) + Xtheta_akl * (vrr_2_000);
    double e_trans0_000_200 = Xqc * (e_trans0_000_100) + Xtheta_akl * (e_trans1_000_100);
    e_trans0_000_200 += 0.5/akl * (vrr_0_000 - theta_akl*(vrr_1_000));
    double vrr_3_000 = Kabcd * _gamma_inc[3];
    double e_trans2_000_100 = Xqc * (vrr_2_000) + Xtheta_akl * (vrr_3_000);
    double e_trans1_000_200 = Xqc * (e_trans1_000_100) + Xtheta_akl * (e_trans2_000_100);
    e_trans1_000_200 += 0.5/akl * (vrr_1_000 - theta_akl*(vrr_2_000));
    double e_trans0_000_300 = Xqc * (e_trans0_000_200) + Xtheta_akl * (e_trans1_000_200);
    e_trans0_000_300 += 1.0/akl * (e_trans0_000_100 - theta_akl*(e_trans1_000_100));
    double e_trans0_000_210 = Yqc * (e_trans0_000_200) + Ytheta_akl * (e_trans1_000_200);
    double e_trans0_000_201 = Zqc * (e_trans0_000_200) + Ztheta_akl * (e_trans1_000_200);
    double e_trans0_000_110 = Yqc * (e_trans0_000_100) + Ytheta_akl * (e_trans1_000_100);
    double e_trans1_000_110 = Yqc * (e_trans1_000_100) + Ytheta_akl * (e_trans2_000_100);
    double e_trans0_000_120 = Yqc * (e_trans0_000_110) + Ytheta_akl * (e_trans1_000_110);
    e_trans0_000_120 += 0.5/akl * (e_trans0_000_100 - theta_akl*(e_trans1_000_100));
    double e_trans0_000_111 = Zqc * (e_trans0_000_110) + Ztheta_akl * (e_trans1_000_110);
    double e_trans0_000_101 = Zqc * (e_trans0_000_100) + Ztheta_akl * (e_trans1_000_100);
    double e_trans1_000_101 = Zqc * (e_trans1_000_100) + Ztheta_akl * (e_trans2_000_100);
    double e_trans0_000_102 = Zqc * (e_trans0_000_101) + Ztheta_akl * (e_trans1_000_101);
    e_trans0_000_102 += 0.5/akl * (e_trans0_000_100 - theta_akl*(e_trans1_000_100));
    double e_trans0_000_010 = Yqc * (vrr_0_000) + Ytheta_akl * (vrr_1_000);
    double e_trans1_000_010 = Yqc * (vrr_1_000) + Ytheta_akl * (vrr_2_000);
    double e_trans0_000_020 = Yqc * (e_trans0_000_010) + Ytheta_akl * (e_trans1_000_010);
    e_trans0_000_020 += 0.5/akl * (vrr_0_000 - theta_akl*(vrr_1_000));
    double e_trans2_000_010 = Yqc * (vrr_2_000) + Ytheta_akl * (vrr_3_000);
    double e_trans1_000_020 = Yqc * (e_trans1_000_010) + Ytheta_akl * (e_trans2_000_010);
    e_trans1_000_020 += 0.5/akl * (vrr_1_000 - theta_akl*(vrr_2_000));
    double e_trans0_000_030 = Yqc * (e_trans0_000_020) + Ytheta_akl * (e_trans1_000_020);
    e_trans0_000_030 += 1.0/akl * (e_trans0_000_010 - theta_akl*(e_trans1_000_010));
    double e_trans0_000_021 = Zqc * (e_trans0_000_020) + Ztheta_akl * (e_trans1_000_020);
    double e_trans0_000_011 = Zqc * (e_trans0_000_010) + Ztheta_akl * (e_trans1_000_010);
    double e_trans1_000_011 = Zqc * (e_trans1_000_010) + Ztheta_akl * (e_trans2_000_010);
    double e_trans0_000_012 = Zqc * (e_trans0_000_011) + Ztheta_akl * (e_trans1_000_011);
    e_trans0_000_012 += 0.5/akl * (e_trans0_000_010 - theta_akl*(e_trans1_000_010));
    double e_trans0_000_001 = Zqc * (vrr_0_000) + Ztheta_akl * (vrr_1_000);
    double e_trans1_000_001 = Zqc * (vrr_1_000) + Ztheta_akl * (vrr_2_000);
    double e_trans0_000_002 = Zqc * (e_trans0_000_001) + Ztheta_akl * (e_trans1_000_001);
    e_trans0_000_002 += 0.5/akl * (vrr_0_000 - theta_akl*(vrr_1_000));
    double e_trans2_000_001 = Zqc * (vrr_2_000) + Ztheta_akl * (vrr_3_000);
    double e_trans1_000_002 = Zqc * (e_trans1_000_001) + Ztheta_akl * (e_trans2_000_001);
    e_trans1_000_002 += 0.5/akl * (vrr_1_000 - theta_akl*(vrr_2_000));
    double e_trans0_000_003 = Zqc * (e_trans0_000_002) + Ztheta_akl * (e_trans1_000_002);
    e_trans0_000_003 += 1.0/akl * (e_trans0_000_001 - theta_akl*(e_trans1_000_001));
    eri[0] = e_trans0_000_300;
    eri[1] = e_trans0_000_210;
    eri[2] = e_trans0_000_201;
    eri[3] = e_trans0_000_120;
    eri[4] = e_trans0_000_111;
    eri[5] = e_trans0_000_102;
    eri[6] = e_trans0_000_030;
    eri[7] = e_trans0_000_021;
    eri[8] = e_trans0_000_012;
    eri[9] = e_trans0_000_003;
}

