    double hrr_000_000_300_110 = (hrr_000_000_310_100) + Ycd * (hrr_000_000_300_100);
    double e_trans0_000_401 = Zqc * (e_trans0_000_400) + Ztheta_akl * (e_trans1_000_400);
    double e_trans0_000_301 = Zqc * (e_trans0_000_300) + Ztheta_akl * (e_trans1_000_300);
