    double hrr_000_000_301_001 = (e_trans0_000_302) + Zcd * (e_trans0_000_301);
    double hrr_000_000_300_001 = (e_trans0_000_301) + Zcd * (e_trans0_000_300);
    double hrr_000_000_300_002 = (hrr_000_000_301_001) + Zcd * (hrr_000_000_300_001);
    double e_trans0_000_210 = Yqc * (e_trans0_000_200) + Ytheta_akl * (e_trans1_000_200);
