    double vrr_2_000 = Kabcd * _gamma_inc[2];
    double vrr_1_100 = Xpa*((vrr_1_000)) - Xtheta_aij*((vrr_2_000));
    double e_trans0_100_100 = Xqc * (vrr_0_100) + Xtheta_akl * (vrr_1_100);
    e_trans0_100_100 += 0.5/aa * (vrr_1_000);
    double e_trans0_000_100 = Xqc * (vrr_0_000) + Xtheta_akl * (vrr_1_000);
    double hrr_000_100_100_000 = (e_trans0_100_100) + Xab * (e_trans0_000_100);
    double hrr_000_100_000_000 = (vrr_0_100) + Xab * (vrr_0_000);
    double hrr_000_100_000_100 = (hrr_000_100_100_000) + Xcd * (hrr_000_100_000_000);
    double e_trans0_100_010 = Yqc * (vrr_0_100) + Ytheta_akl * (vrr_1_100);
    double e_trans0_000_010 = Yqc * (vrr_0_000) + Ytheta_akl * (vrr_1_000);
    double hrr_000_100_010_000 = (e_trans0_100_010) + Xab * (e_trans0_000_010);
    double hrr_000_100_000_010 = (hrr_000_100_010_000) + Ycd * (hrr_000_100_000_000);
    double e_trans0_100_001 = Zqc * (vrr_0_100) + Ztheta_akl * (vrr_1_100);
    double e_trans0_000_001 = Zqc * (vrr_0_000) + Ztheta_akl * (vrr_1_000);
    double hrr_000_100_001_000 = (e_trans0_100_001) + Xab * (e_trans0_000_001);
    double hrr_000_100_000_001 = (hrr_000_100_001_000) + Zcd * (hrr_000_100_000_000);
    double vrr_0_010 = Ypa*(vrr_0_000) - Ytheta_aij*(vrr_1_000);
    double vrr_1_010 = Ypa*(vrr_1_000) - Ytheta_aij*(vrr_2_000);
    double e_trans0_010_100 = Xqc * (vrr_0_010) + Xtheta_akl * (vrr_1_010);
    double hrr_000_010_100_000 = (e_trans0_010_100) + Yab * (e_trans0_000_100);
    double hrr_000_010_000_000 = (vrr_0_010) + Yab * (vrr_0_000);
    double hrr_000_010_000_100 = (hrr_000_010_100_000) + Xcd * (hrr_000_010_000_000);
    double e_trans0_010_010 = Yqc * (vrr_0_010) + Ytheta_akl * (vrr_1_010);
    e_trans0_010_010 += 0.5/aa * (vrr_1_000);
    double hrr_000_010_010_000 = (e_trans0_010_010) + Yab * (e_trans0_000_010);
    double hrr_000_010_000_010 = (hrr_000_010_010_000) + Ycd * (hrr_000_010_000_000);
    double e_trans0_010_001 = Zqc * (vrr_0_010) + Ztheta_akl * (vrr_1_010);
    double hrr_000_010_001_000 = (e_trans0_010_001) + Yab * (e_trans0_000_001);
    double hrr_000_010_000_001 = (hrr_000_010_001_000) + Zcd * (hrr_000_010_000_000);
    double vrr_0_001 = Zpa*(vrr_0_000) - Ztheta_aij*(vrr_1_000);
    double vrr_1_001 = Zpa*(vrr_1_000) - Ztheta_aij*(vrr_2_000);
    double e_trans0_001_100 = Xqc * (vrr_0_001) + Xtheta_akl * (vrr_1_001);
