    double e_trans0_001_001 = Zqc * (vrr_0_001) + Ztheta_akl * (vrr_1_001);
    e_trans0_001_001 += 0.5/aa * (vrr_1_000);
    double hrr_000_001_001_000 = (e_trans0_001_001) + Zab * (e_trans0_000_001);
    double hrr_000_001_000_001 = (hrr_000_001_001_000) + Zcd * (hrr_000_001_000_000);
    eri[0] = hrr_000_100_000_100;
    eri[1] = hrr_000_100_000_010;
