    e_trans0_000_200 += 0.5/akl * (vrr_0_000 - theta_akl*(vrr_1_000));
    double hrr_000_100_200_000 = (e_trans0_100_200) + Xab * (e_trans0_000_200);
    double e_trans0_100_110 = Yqc * (e_trans0_100_100) + Ytheta_akl * (e_trans1_100_100);
