void run_eri_2010(double *eri, double ai, double aj, double ak, double al,
        double *Ra, double *Rb, double *Rc, double *Rd,
        void (*gamma_inc_fn)(int, double, double []))
{
    extern double exp(double);
    extern double sqrt(double);
    double aij = ai + aj;
    double akl = ak + al;
    double theta = aij * akl / (aij + akl);
    double Xab = Ra[0] - Rb[0];
    double Yab = Ra[1] - Rb[1];
    double Zab = Ra[2] - Rb[2];
    double Xcd = Rc[0] - Rd[0];
    double Ycd = Rc[1] - Rd[1];
    double Zcd = Rc[2] - Rd[2];
    double theta_rij = ai * aj / aij * (Xab*Xab+Yab*Yab+Zab*Zab);
    double theta_rkl = ak * al / akl * (Xcd*Xcd+Ycd*Ycd+Zcd*Zcd);
    double fac = 34.986836655249725; // 2*pi**2.5
    double Kabcd = fac / (aij*akl*sqrt(aij+akl)) * exp(-theta_rij - theta_rkl);
    if (Kabcd < 1e-16) {
        for (int i = 0; i < 18; i++) eri[i] = 0;
        return;
    }
    double Xp = (ai * Ra[0] + aj * Rb[0]) / aij;
    double Yp = (ai * Ra[1] + aj * Rb[1]) / aij;
    double Zp = (ai * Ra[2] + aj * Rb[2]) / aij;
    double Xq = (ak * Rc[0] + al * Rd[0]) / akl;
    double Yq = (ak * Rc[1] + al * Rd[1]) / akl;
    double Zq = (ak * Rc[2] + al * Rd[2]) / akl;
    double Xpq = Xp - Xq;
    double Ypq = Yp - Yq;
    double Zpq = Zp - Zq;
    double Xpa = Xp - Ra[0];
    double Ypa = Yp - Ra[1];
    double Zpa = Zp - Ra[2];
    double Xqc = Xq - Rc[0];
    double Yqc = Yq - Rc[1];
    double Zqc = Zq - Rc[2];
    double theta_r2 = theta * (Xpq*Xpq+Ypq*Ypq+Zpq*Zpq);
    double theta_aij = theta / aij;
    double theta_akl = theta / akl;
    double aij_akl = aij / akl;
    double aa = aij + akl;
    double Xtheta_aij = Xpq * theta_aij;
    double Ytheta_aij = Ypq * theta_aij;
    double Ztheta_aij = Zpq * theta_aij;
    double Xtheta_akl = Xpq * theta_akl;
    double Ytheta_akl = Ypq * theta_akl;
    double Ztheta_akl = Zpq * theta_akl;
    double _gamma_inc[32];
    gamma_inc_fn(4, theta_r2, _gamma_inc);
    double vrr_0_000 = Kabcd * _gamma_inc[0];
    double vrr_1_000 = Kabcd * _gamma_inc[1];
    double vrr_0_100 = Xpa*((vrr_0_000)) - Xtheta_aij*((vrr_1_000));
    double vrr_2_000 = Kabcd * _gamma_inc[2];
    double vrr_1_100 = Xpa*((vrr_1_000)) - Xtheta_aij*((vrr_2_000));
    double vrr_0_200 = Xpa*((vrr_0_100)) - Xtheta_aij*((vrr_1_100));
    vrr_0_200 += 0.5/aij * ((vrr_0_000) - theta_aij*(vrr_1_000));
    double vrr_3_000 = Kabcd * _gamma_inc[3];
    double vrr_2_100 = Xpa*((vrr_2_000)) - Xtheta_aij*((vrr_3_000));
    double vrr_1_200 = Xpa*((vrr_1_100)) - Xtheta_aij*((vrr_2_100));
    vrr_1_200 += 0.5/aij * ((vrr_1_000) - theta_aij*(vrr_2_000));
    double e_trans0_200_100 = Xqc * (vrr_0_200) + Xtheta_akl * (vrr_1_200);
    e_trans0_200_100 += 1.0/aa * (vrr_1_100);
    double e_trans0_200_010 = Yqc * (vrr_0_200) + Ytheta_akl * (vrr_1_200);
    double e_trans0_200_001 = Zqc * (vrr_0_200) + Ztheta_akl * (vrr_1_200);
    double vrr_0_110 = Ypa*(vrr_0_100) - Ytheta_aij*(vrr_1_100);
    double vrr_1_110 = Ypa*(vrr_1_100) - Ytheta_aij*(vrr_2_100);
    double e_trans0_110_100 = Xqc * (vrr_0_110) + Xtheta_akl * (vrr_1_110);
    double vrr_1_010 = Ypa*(vrr_1_000) - Ytheta_aij*(vrr_2_000);
    e_trans0_110_100 += 0.5/aa * (vrr_1_010);
    double e_trans0_110_010 = Yqc * (vrr_0_110) + Ytheta_akl * (vrr_1_110);
    e_trans0_110_010 += 0.5/aa * (vrr_1_100);
    double e_trans0_110_001 = Zqc * (vrr_0_110) + Ztheta_akl * (vrr_1_110);
    double vrr_0_101 = Zpa*(vrr_0_100) - Ztheta_aij*(vrr_1_100);
    double vrr_1_101 = Zpa*(vrr_1_100) - Ztheta_aij*(vrr_2_100);
    double e_trans0_101_100 = Xqc * (vrr_0_101) + Xtheta_akl * (vrr_1_101);
    double vrr_1_001 = Zpa*(vrr_1_000) - Ztheta_aij*(vrr_2_000);
    e_trans0_101_100 += 0.5/aa * (vrr_1_001);
    double e_trans0_101_010 = Yqc * (vrr_0_101) + Ytheta_akl * (vrr_1_101);
    double e_trans0_101_001 = Zqc * (vrr_0_101) + Ztheta_akl * (vrr_1_101);
    e_trans0_101_001 += 0.5/aa * (vrr_1_100);
    double vrr_0_010 = Ypa*(vrr_0_000) - Ytheta_aij*(vrr_1_000);
    double vrr_0_020 = Ypa*(vrr_0_010) - Ytheta_aij*(vrr_1_010);
    vrr_0_020 += 0.5/aij * ((vrr_0_000) - theta_aij*(vrr_1_000));
    double vrr_2_010 = Ypa*(vrr_2_000) - Ytheta_aij*(vrr_3_000);
    double vrr_1_020 = Ypa*(vrr_1_010) - Ytheta_aij*(vrr_2_010);
    vrr_1_020 += 0.5/aij * ((vrr_1_000) - theta_aij*(vrr_2_000));
    double e_trans0_020_100 = Xqc * (vrr_0_020) + Xtheta_akl * (vrr_1_020);
    double e_trans0_020_010 = Yqc * (vrr_0_020) + Ytheta_akl * (vrr_1_020);
    e_trans0_020_010 += 1.0/aa * (vrr_1_010);
    double e_trans0_020_001 = Zqc * (vrr_0_020) + Ztheta_akl * (vrr_1_020);
    double vrr_0_011 = Zpa*(vrr_0_010) - Ztheta_aij*(vrr_1_010);
    double vrr_1_011 = Zpa*(vrr_1_010) - Ztheta_aij*(vrr_2_010);
    double e_trans0_011_100 = Xqc * (vrr_0_011) + Xtheta_akl * (vrr_1_011);
    double e_trans0_011_010 = Yqc * (vrr_0_011) + Ytheta_akl * (vrr_1_011);
    e_trans0_011_010 += 0.5/aa * (vrr_1_001);
    double e_trans0_011_001 = Zqc * (vrr_0_011) + Ztheta_akl * (vrr_1_011);
    e_trans0_011_001 += 0.5/aa * (vrr_1_010);
    double vrr_0_001 = Zpa*(vrr_0_000) - Ztheta_aij*(vrr_1_000);
    double vrr_0_002 = Zpa*(vrr_0_001) - Ztheta_aij*(vrr_1_001);
    vrr_0_002 += 0.5/aij * ((vrr_0_000) - theta_aij*(vrr_1_000));
    double vrr_2_001 = Zpa*(vrr_2_000) - Ztheta_aij*(vrr_3_000);
    double vrr_1_002 = Zpa*(vrr_1_001) - Ztheta_aij*(vrr_2_001);
    vrr_1_002 += 0.5/aij * ((vrr_1_000) - theta_aij*(vrr_2_000));
    double e_trans0_002_100 = Xqc * (vrr_0_002) + Xtheta_akl * (vrr_1_002);
    double e_trans0_002_010 = Yqc * (vrr_0_002) + Ytheta_akl * (vrr_1_002);
    double e_trans0_002_001 = Zqc * (vrr_0_002) + Ztheta_akl * (vrr_1_002);
    e_trans0_002_001 += 1.0/aa * (vrr_1_001);
    eri[0] = e_trans0_200_100;
    eri[1] = e_trans0_200_010;
    eri[2] = e_trans0_200_001;
    eri[3] = e_trans0_110_100;
    eri[4] = e_trans0_110_010;
    eri[5] = e_trans0_110_001;
    eri[6] = e_trans0_101_100;
    eri[7] = e_trans0_101_010;
    eri[8] = e_trans0_101_001;
    eri[9] = e_trans0_020_100;
    eri[10] = e_trans0_020_010;
    eri[11] = e_trans0_020_001;
    eri[12] = e_trans0_011_100;
    eri[13] = e_trans0_011_010;
    eri[14] = e_trans0_011_001;
    eri[15] = e_trans0_002_100;
    eri[16] = e_trans0_002_010;
    eri[17] = e_trans0_002_001;
}

