    double vrr_0_200 = Xpa*((vrr_0_100)) - Xtheta_aij*((vrr_1_100));
    vrr_0_200 += 0.5/aij * ((vrr_0_000) - theta_aij*(vrr_1_000));
    double vrr_3_000 = Kabcd * _gamma_inc[3];
    double vrr_2_100 = Xpa*((vrr_2_000)) - Xtheta_aij*((vrr_3_000));
