    vrr_1_200 += 0.5/aij * ((vrr_1_000) - theta_aij*(vrr_2_000));
    double vrr_0_300 = Xpa*((vrr_0_200)) - Xtheta_aij*((vrr_1_200));
    vrr_0_300 += 1.0/aij * ((vrr_0_100) - theta_aij*(vrr_1_100));
    double vrr_4_000 = Kabcd * _gamma_inc[4];
    double vrr_3_100 = Xpa*((vrr_3_000)) - Xtheta_aij*((vrr_4_000));
    double vrr_2_200 = Xpa*((vrr_2_100)) - Xtheta_aij*((vrr_3_100));
    vrr_2_200 += 0.5/aij * ((vrr_2_000) - theta_aij*(vrr_3_000));
    double vrr_1_300 = Xpa*((vrr_1_200)) - Xtheta_aij*((vrr_2_200));
    vrr_1_300 += 1.0/aij * ((vrr_1_100) - theta_aij*(vrr_2_100));
    double vrr_0_400 = Xpa*((vrr_0_300)) - Xtheta_aij*((vrr_1_300));
    vrr_0_400 += 1.5/aij * ((vrr_0_200) - theta_aij*(vrr_1_200));
