    double vrr_4_100 = Xpa*((vrr_4_000)) - Xtheta_aij*((vrr_5_000));
    double vrr_3_200 = Xpa*((vrr_3_100)) - Xtheta_aij*((vrr_4_100));
    vrr_3_200 += 0.5/aij * ((vrr_3_000) - theta_aij*(vrr_4_000));
    double vrr_2_300 = Xpa*((vrr_2_200)) - Xtheta_aij*((vrr_3_200));
    vrr_2_300 += 1.0/aij * ((vrr_2_100) - theta_aij*(vrr_3_100));
    double vrr_1_400 = Xpa*((vrr_1_300)) - Xtheta_aij*((vrr_2_300));
    vrr_1_400 += 1.5/aij * ((vrr_1_200) - theta_aij*(vrr_2_200));
    double e_trans0_400_100 = Xqc * (vrr_0_400) + Xtheta_akl * (vrr_1_400);
    e_trans0_400_100 += 2.0/aa * (vrr_1_300);
    double e_trans0_400_010 = Yqc * (vrr_0_400) + Ytheta_akl * (vrr_1_400);
    double e_trans0_400_001 = Zqc * (vrr_0_400) + Ztheta_akl * (vrr_1_400);
